 1	import React from 'react';
 2	import { Link } from 'react-router-dom-v5-compat';
 3	
 4	import { VirtualMachineDetailsTab } from '@kubevirt-utils/constants/tabs-constants';
 5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 6	import useDisksTableData from '@kubevirt-utils/resources/vm/hooks/disk/useDisksTableData';
 7	import { DiskRowDataLayout } from '@kubevirt-utils/resources/vm/utils/disk/constants';
 8	import { VirtualizedTable } from '@openshift-console/dynamic-plugin-sdk';
 9	import { Card, CardBody, CardTitle, Divider } from '@patternfly/react-core';
10	
11	import { createURL } from '../../utils/utils';
12	
13	import useVirtualMachinesOverviewTabDisksColumns from './hooks/useVirtualMachinesOverviewTabDisksColumns';
14	import VirtualMachinesOverviewTabDisksRow from './VirtualMachinesOverviewTabDisksRow';
15	
16	import './virtual-machines-overview-tab-disks.scss';
17	
18	const VirtualMachinesOverviewTabDisks = ({ vm, vmi }) => {
19	  const [disks, loaded, loadedError] = useDisksTableData(vm, vmi);
20	  const { t } = useKubevirtTranslation();
21	  const columns = useVirtualMachinesOverviewTabDisksColumns();
22	
23	  return (
24	    <div className="VirtualMachinesOverviewTabDisks--main">
25	      <Card>
26	        <CardTitle className="text-muted">
27	          <Link
28	            to={createURL(
29	              `${VirtualMachineDetailsTab.Configurations}/${VirtualMachineDetailsTab.Storage}`,
30	              location?.pathname,
31	            )}
32	          >
33	            {t('Storage ({{disks}})', { disks: disks.length || 0 })}
34	          </Link>
35	        </CardTitle>
36	        <Divider />
37	        <CardBody isFilled>
38	          <VirtualizedTable<DiskRowDataLayout>
39	            columns={columns}
40	            data={disks}
41	            loaded={loaded}
42	            loadError={loadedError}
43	            Row={VirtualMachinesOverviewTabDisksRow}
44	            unfilteredData={disks}
45	          />
46	        </CardBody>
47	      </Card>
48	    </div>
49	  );
50	};
51	
52	export default VirtualMachinesOverviewTabDisks;

